sql:
SELECT *
FROM motion_data
WHERE data_id = 1;

SELECT DISTINCT sensor_id
FROM motion_data
WHERE data_quality = 'bad';

external_knowledge:
- 'Stars' refer to the data points;
- 'Shine the brightest' refers to having the highest sampling rate;
- 'Constellation of each sensor' means the data points associated with each sensor;
- 'Identity' refers to the sensor ID and name;
- 'Time of their shining' refers to the timestamp;
- 'Clarity of their light' refers to the data quality;
- 'Source of their radiance' refers to the data source.

sql:
SELECT md.sensor_id, md.data_quality
FROM motion_data md
WHERE md.sensor_id = 0 AND md.data_quality = 'good';

SELECT COUNT(DISTINCT sensor_type) 
FROM sensors 
WHERE status = 'active';

SELECT DISTINCT sensor_id
FROM motion_data
WHERE sampling_rate = (SELECT MAX(sampling_rate) FROM motion_data);
